<template>
    <section class="section_slider">
      <div
        class="slider_wrapper"
        @touchstart="touchStart"
        @touchmove="touchMove"
        @touchend="touchEnd"
      >
        <div class="slider" :style="{ transform: `translateX(-${currentIndex * slideWidth}%)` }">
          <div v-for="(slide, index) in slides" :key="index" class="slide">
            <img :src="slide.image" :alt="'Slide ' + (index + 1)" />
          </div>
        </div>
      </div>
      <div class="dots_wrapper d-flex align-items-center">
        <img src="../assets/main/arrow-left.svg" class="arrow" @click="prevSlide" />
        <div class="dots">
          <button v-for="(dot, index) in dotCount" :key="index" :class="{ active: currentIndex === index }" @click="goToSlide(index)" class="dot"></button>
        </div>
        <img src="../assets/main/arrow-right.svg" class="arrow" @click="nextSlide" />
      </div>
    </section>
  </template>
  
  
  <script>
  export default {
    data() {
      return {
        currentIndex: 0,
        startX: 0,
        slidesPerView: 1,
        slideWidth: 100,
        slides: [
          { image: require('../assets/main/bonus_v1_RU.png') },
          { image: require('../assets/main/bonus-slides.png') },
          { image: require('../assets/main/bonus_v1_RU.png') },
          { image: require('../assets/main/bonus-slides.png') },
          { image: require('../assets/main/bonus_v1_RU.png') },
        ],
      };
    },
    computed: {
      dotCount() {
        return Math.ceil(this.slides.length / this.slidesPerView);
      }
    },
    mounted() {
      this.updateSlidesPerView();
      window.addEventListener('resize', this.updateSlidesPerView);
    },
    beforeUnmount() {
      window.removeEventListener('resize', this.updateSlidesPerView);
    },
    methods: {
      touchStart(event) {
        this.startX = event.touches[0].clientX;
      },
      touchMove(event) {
        this.endX = event.touches[0].clientX;
      },
      touchEnd() {
        const diffX = this.startX - this.endX;
        if (diffX > 50) {
          this.nextSlide();
        } else if (diffX < -50) {
          this.prevSlide();
        }
        this.startX = 0;
        this.endX = 0;
      },
      updateSlidesPerView() {
        if (window.innerWidth > 768) {
          this.slidesPerView = 2;
        } else {
          this.slidesPerView = 1;
        }
        this.slideWidth = 100 / this.slidesPerView;
      },
      prevSlide() {
        if (this.currentIndex > 0) {
          this.currentIndex--;
        } else {
          this.currentIndex = this.dotCount - 1;
        }
      },
      nextSlide() {
        if (this.currentIndex < this.dotCount - 1) {
          this.currentIndex++;
        } else {
          this.currentIndex = 0;
        }
      },
      goToSlide(index) {
        this.currentIndex = index;
      },
    },
  };
  </script>
  <style scoped>
  .section_slider {
    position: relative;
    width: 100%;
    margin: auto;
    overflow: hidden;
  }
  
  .slider_wrapper {
    overflow: hidden;
  }
  
  .slider {
    display: flex;
    transition: transform 0.5s ease;
  }
  
  .slide {
    flex: 0 0 100%;
    transition: transform 0.5s ease;
  }
  
  .slide img {
    width: 100%;
    display: block;
  }
  
  .dots_wrapper {
    display: flex;
    justify-content: center;
    align-items: center;
    margin-top: 20px;
  }
  
  .arrow {
    background: none;
    border: none;
    cursor: pointer;
  }
  
  .dots {
    display: flex;
    margin: 0 10px;
  }
  
  .dot {
    width: 14px;
    height: 5px;
    background-color: #1B1C1E;
    border-radius: 30px;
    margin: 0 5px;
    cursor: pointer;
    border: none;
    outline: none;
    transition: all 0.3s ease;
  }
  
  .dot.active {
    background-color: #606060;
    width: 30px;
    transition: all 0.3s ease;
  }
  
  /* Медиазапросы для адаптации слайдов */
  @media (min-width: 768px) {
    .slide {
      flex: 0 0 calc(50% - 15px); /* 2 слайда в ряду для экранов шире 768px */
      margin-right: 20px;
    }
  }
  
  @media (max-width: 767px) {
    .slide {
      flex: 0 0 100%; /* 1 слайд в ряду для экранов уже 767px */
      margin-right: 0; /* Убираем отступ на мобильных */
    }
  }
  </style>
  