<template>
  <div class="layout">
    <HeaderComponent @toggle-sidebar="handleSidebarToggle" :is-authenticated="isAuthenticated" @login="handleLogin" @logout="handleLogout" @toggle-account="handleToggleAccount" :expandedAccount="expandedAccount"  :isSmallScreen="isSmallScreen" />
    <div :class="['main-content', { 'sidebar-collapsed': isSidebarCollapsed }]">
      <LeftSidebar :collapsed="isSidebarCollapsed" :isSmallScreen="isSmallScreen" :isTinyScreen="isTinyScreen" />
      <div class="content-container">
        <main class="content">
          <MainContent />
          <FooterComponent />
          <MobileHeader v-if="isMobile || isSmallScreen" :is-authenticated="isAuthenticated" @toggle-sidebar="handleSidebarToggle" :collapsed="isSidebarCollapsed" @toggle-account="handleToggleAccount" :expandedAccount="expandedAccount"/>
        </main>
      </div>
      <RightSidebar v-if="!isMobile && !isTinyScreen" />
    </div>
  </div>
</template>

<script>
import MobileDetect from 'mobile-detect';
import { provide } from 'vue';
import HeaderComponent from './Header.vue'
import FooterComponent from './Footer.vue'
import LeftSidebar from './LeftSidebar.vue'
import RightSidebar from './RightSidebar.vue'
import MobileHeader from './MobileHeader.vue'
import MainContent from './MainContent.vue'

export default {
  name: 'MainLayout',
  components: {
    HeaderComponent,
    FooterComponent,
    LeftSidebar,
    RightSidebar,
    MobileHeader,
    MainContent
  },
  data() {
    return {
      isSidebarCollapsed: false,
      isSmallScreen: window.innerWidth < 1253,
      isTinyScreen: window.innerWidth < 950,
      isMobile: false,
      isAuthenticated: false,
      expandedAccount: false,
    };
  },
  created() {
    const md = new MobileDetect(window.navigator.userAgent);
    this.isMobile = !!md.mobile();
    provide('isMobile', this.isMobile);

    this.isSidebarCollapsed = this.isMobile || this.isTinyScreen; // true для мобильных устройств, false для десктопов
  },
  mounted() {
    window.addEventListener('resize', this.updateScreenSize);
  },
  beforeUnmount() {
    window.removeEventListener('resize', this.updateScreenSize);
  },
  methods: {
    updateScreenSize() {
      this.isSmallScreen = window.innerWidth < 1253;
      this.isTinyScreen = window.innerWidth < 950;
    },
    handleSidebarToggle(collapsed) {
      this.isSidebarCollapsed = collapsed;
    },
    handleLogin() {
      this.isAuthenticated = true;
    },
    handleLogout() {
      this.isAuthenticated = false;
    },
    handleToggleAccount() {
      this.expandedAccount = !this.expandedAccount;
    }
  }
}
</script>

<style lang="scss">
.layout {
  display: flex;
  flex-direction: column;
  height: 100vh;
  

  .main-content {
    display: flex;
    flex-grow: 1;
    overflow: hidden;
    transition: all 0.3s ease;

    &.sidebar-collapsed .left-sidebar {
      width: 50px; /* Ширина при свернутом состоянии */
    }

    &.sidebar-collapsed .content-container {
      flex-grow: 1;
    }
  }

  .content-container {
    display: flex;
    flex-direction: column;
    flex-grow: 1;
    overflow-y: auto;

  }

  .content {
    flex-grow: 1;
    padding: 1rem;
  }
}


// animation of drowdowns
@keyframes fade-in {
  0% {
    opacity: 0;
    transform: translateY(10px); /* Появление с небольшого смещения */
  }
  100% {
    opacity: 1;
    transform: translateY(0); /* Конечное положение */
  }
}

@keyframes fade-out {
  0% {
    opacity: 1;
    transform: translateY(0); /* Исходное положение */
  }
  100% {
    opacity: 0;
    transform: translateY(10px); /* Исчезновение с небольшим смещением */
  }
}

.fade-enter-active {
  animation: fade-in 0.5s;
}

.fade-leave-active {
  animation: fade-out 0.5s;
}


// Toggle switches
.toggle-switch {
    width: 41px;
    height: 20px;
    border-radius: 17px;
    background-color: #777777;
    position: relative;
    cursor: pointer;
    transition: background-color 0.3s;
}

.toggle-switch-on {
  background-color: #5BC32A;
}

.toggle-switch-inner {
  width: 100%;
  height: 100%;
  border-radius: 17px;
  display: flex;
  align-items: center;
  transition: background-color 0.3s;
}

.toggle-switch-knob {
  width: 15px;
    height: 15px;
    border-radius: 50%;
    background-color: #EEEEEE;
    position: absolute;
    left: 3px;
    transition: transform 0.3s;
}

.toggle-switch-on .toggle-switch-knob {
  transform: translateX(19px);
}

/* Стилизация скроллбара для Webkit-браузеров (Chrome, Safari) */
.content-container::-webkit-scrollbar {
  width: 8px; /* Ширина скроллбара */
}

.content-container::-webkit-scrollbar-track {
  background: rgb(17, 18, 20); /* Цвет фона трека скроллбара */
}

.content-container::-webkit-scrollbar-thumb {
  background: #4c4f56; /* Цвет ползунка скроллбара */
  border-radius: 10px; /* Радиус скругления ползунка */
}

.content-container::-webkit-scrollbar-thumb:hover {
  background: #6c6f76; /* Цвет ползунка при наведении */
}




@media screen and (max-width:768px) {
.main-content {
  margin-top: 80px;
}
}

</style>
